#include <pthread.h>
#include <stdio.h>
#include <errno.h>
#include <stdlib.h>
#include <unistd.h>

#include "disco.h"

/*
 * Implementacion del problema de la discoteca.
 *
 * Metodologia:
 *   - Un solo mutex (m) y una sola condicion (c).
 *   - Distribuidores de tickets para damas y varones:
 *       num_dama   : proximo ticket a asignar a una dama
 *       turno_dama : proximo ticket a servir (dama mas antigua esperando)
 *       num_varon   : proximo ticket a asignar a un varon
 *       turno_varon : proximo ticket a servir (varon mas antiguo esperando)
 *     "num - turno" cuenta cuantos hay esperando de ese sexo.
 *   - Si al llegar hay personas del sexo opuesto esperando, se
 *     aparea inmediatamente con la mas antigua (la del ticket
 *     turno_*) y retorna el nombre de su pareja.
 *   - Si no hay nadie del sexo opuesto, se asigna un ticket, se
 *     registra el nombre y se espera en la condicion hasta que
 *     alguien del sexo opuesto lo retire y deposite el nombre
 *     de la pareja en la celda pareja_dama[ticket%MAX] (o
 *     pareja_varon[ticket%MAX]).
 *
 * No se usan colas FIFO: los tickets son el orden de llegada.
 * No hay busy-waiting: pthread_cond_wait bloquea al thread.
 */

#define MAX 1024

static pthread_mutex_t m;
static pthread_cond_t  c;

static int num_dama   = 0;
static int turno_dama = 0;
static int num_varon   = 0;
static int turno_varon = 0;

static char *nom_dama[MAX];
static char *nom_varon[MAX];
static char *pareja_dama[MAX];
static char *pareja_varon[MAX];

void discoInit(void) {
    pthread_mutex_init(&m, NULL);
    pthread_cond_init(&c, NULL);
}

void discoDestroy(void) {
    pthread_cond_destroy(&c);
    pthread_mutex_destroy(&m);
}

char *dama(char *nom) {
    pthread_mutex_lock(&m);

    /* Si hay varones esperando, apareo inmediatamente con el mas antiguo.
     * En este caso no asigno ticket ni dejo a la dama en espera,
     * de modo que en ningun momento quedan damas y varones esperando
     * simultaneamente. */
    if (turno_varon < num_varon) {
        char *pareja = nom_varon[turno_varon % MAX];
        nom_varon[turno_varon % MAX]    = NULL;
        pareja_varon[turno_varon % MAX] = nom;
        turno_varon++;
        pthread_cond_broadcast(&c);
        pthread_mutex_unlock(&m);
        return pareja;
    }

    /* No hay varones esperando: la dama se registra y espera. */
    int my_ticket = num_dama++;
    nom_dama[my_ticket % MAX] = nom;

    /* Espera pasiva hasta que un varon deposite aqui el nombre
     * de su pareja. El while cubre wakeups spurios y casos en
     * que se despierte otra dama. */
    while (pareja_dama[my_ticket % MAX] == NULL) {
        pthread_cond_wait(&c, &m);
    }

    char *pareja = pareja_dama[my_ticket % MAX];
    pareja_dama[my_ticket % MAX] = NULL;
    nom_dama[my_ticket % MAX]    = NULL;
    pthread_mutex_unlock(&m);
    return pareja;
}

char *varon(char *nom) {
    pthread_mutex_lock(&m);

    /* Si hay damas esperando, apareo inmediatamente con la mas antigua. */
    if (turno_dama < num_dama) {
        int d_ticket = turno_dama;
        char *pareja = nom_dama[d_ticket % MAX];
        nom_dama[d_ticket % MAX]    = NULL;
        pareja_dama[d_ticket % MAX] = nom;
        turno_dama++;
        pthread_cond_broadcast(&c);
        pthread_mutex_unlock(&m);
        return pareja;
    }

    /* No hay damas esperando: el varon se registra y espera. */
    int my_ticket = num_varon++;
    nom_varon[my_ticket % MAX] = nom;

    while (pareja_varon[my_ticket % MAX] == NULL) {
        pthread_cond_wait(&c, &m);
    }

    char *pareja = pareja_varon[my_ticket % MAX];
    pareja_varon[my_ticket % MAX] = NULL;
    nom_varon[my_ticket % MAX]    = NULL;
    pthread_mutex_unlock(&m);
    return pareja;
}

